; Auto-generated by breadbox. Do not edit.
; GPIO group: {{ device_id }} (port {{ port }} on {{ bus_device.id }}, mask {{ bits | hex }})
;
; Subroutine wrappers for {{ device_id }} macros.
; Call via JSR, e.g. `jsr {{ device_id }}::turn_on`.

.include "breadbox.inc"

{% set PORT_REG = bus_device.id ~ "_PORT" ~ port %}
{% set DDR_REG = bus_device.id ~ "_DDR" ~ port %}
{% set MASK = bits | int %}
{% set INV_MASK = 255 - MASK %}
.segment "KERNAL"
{% if default is not none %}

; =========================================================================
; Initialize {{ device_id }}: set DDR to output and apply default ({{ default }}).
;
; Called automatically during boot via .constructor.
;
; Out:
;   A = clobbered

    .proc init_{{ device_id | lower }}
{% if exclusive_port %}
        lda #{{ MASK | hex }}
        sta {{ DDR_REG }}
{% if default == "on" %}
        sta {{ PORT_REG }}
{% else %}
        lda #$00
        sta {{ PORT_REG }}
{% endif %}
{% else %}
        lda {{ DDR_REG }}
        ora #{{ MASK | hex }}
        sta {{ DDR_REG }}
{% if default == "on" %}
        lda {{ PORT_REG }}
        ora #{{ MASK | hex }}
        sta {{ PORT_REG }}
{% else %}
        lda {{ PORT_REG }}
        and #{{ INV_MASK | hex }}
        sta {{ PORT_REG }}
{% endif %}
{% endif %}
        rts
    .endproc
    .constructor init_{{ device_id | lower }}
{% endif %}

.scope {{ device_id }}
{% if direction in ("out", "both") %}

    ; =====================================================================
    ; Set all {{ device_id }} outputs high.
    ;
    ; Out:
    ;   A = clobbered

    .proc turn_on
        {{ device_id }}_on
        rts
    .endproc

    ; =====================================================================
    ; Set all {{ device_id }} outputs low.
    ;
    ; Out:
    ;   A = clobbered

    .proc turn_off
        {{ device_id }}_off
        rts
    .endproc

    ; =====================================================================
    ; Toggle all {{ device_id }} outputs.
    ;
    ; Out:
    ;   A = clobbered

    .proc toggle
        {{ device_id }}_toggle
        rts
    .endproc
{% endif %}
{% if direction in ("in", "both") %}

    ; =====================================================================
    ; Read {{ device_id }} input state.
    ;
    ; Out:
    ;   A = group state (masked to {{ bits | hex }})

    .proc read
        {{ device_id }}_read
        rts
    .endproc
{% endif %}
.endscope
